// // This module calculates the product of two 8-bit numbers when sel is low
module top_module(input [7:0] A, input [7:0] B, input sel, output reg [7:0] result);always @(*) begin
    if(sel == 0) begin
        result = A + B;
    end else begin
        result = A - B;
    end
end

endmodule
